#!/bin/bash
set -e

cd /root/wooji-digital

# Discard any local changes (e.g. package-lock.json regenerated by npm install)
git checkout -- .
git pull origin main

# Re-exec the freshly pulled copy so script/config changes take effect on the
# SAME deploy (bash otherwise keeps executing the pre-pull version of this file).
if [ "${DEPLOY_REEXEC:-}" != "1" ]; then
  export DEPLOY_REEXEC=1
  exec bash "$0"
fi

cd frontend
npm install --production=false

# Build — do NOT remove .next first so the running server stays up during build
# Next.js writes to .next atomically; old build stays available until this completes
NODE_OPTIONS="--max-old-space-size=4096" npm run build

# Stop → start only after successful build (set -e aborts on build failure)
pm2 stop wooji || true
pm2 start wooji --node-args="--max-old-space-size=1024" --max-memory-restart 2G 2>/dev/null || \
  pm2 restart wooji --node-args="--max-old-space-size=1024" --max-memory-restart 2G
pm2 save

# Brief health check
sleep 4
curl -sf http://127.0.0.1:3000/ -o /dev/null && echo "Deploy OK: $(date)" || echo "WARNING: Health check failed — check pm2 logs"

# ── Caddy: lock origin to Cloudflare (idempotent + fail-safe) ──
# Makes CF-Connecting-IP trustworthy by 403ing direct-to-origin (non-Cloudflare)
# requests. Cannot break the live site: applies ONLY if caddy + Caddyfile + the
# site block exist and the candidate passes `caddy validate`; otherwise no-op.
# On reload failure it restores the backup. The `|| true` call site keeps `set -e`
# from ever aborting the (already-successful) app deploy because of this block.
apply_caddy_cf_lock() {
  local CF="/etc/caddy/Caddyfile"
  local SNIP="/root/wooji-digital/deploy/cloudflare-allowlist.caddy"
  command -v caddy >/dev/null 2>&1 || { echo "Caddy: binary not found — skip"; return 0; }
  [ -f "$CF" ]   || { echo "Caddy: $CF not found — skip"; return 0; }
  [ -f "$SNIP" ] || { echo "Caddy: snippet not found — skip"; return 0; }
  grep -q 'cloudflare_only' "$CF" && { echo "Caddy: CF lock already applied — skip"; return 0; }

  local TMP BAK VERR
  TMP="$(mktemp)" || return 0
  BAK="${CF}.bak.$(date +%s)"
  # APPEND the snippet definition at the END (a leading global-options block, if
  # any, must stay first; Caddy resolves snippet imports regardless of order).
  { cat "$CF"; echo; cat "$SNIP"; } > "$TMP"
  # Insert `import cloudflare_only` as the first line inside the woojidigital.com site block
  sed -i -E '0,/^[[:space:]]*[^#].*woojidigital\.com[^{]*\{[[:space:]]*$/s//&\n\timport cloudflare_only/' "$TMP"
  if ! grep -q 'import cloudflare_only' "$TMP"; then
    echo "Caddy: woojidigital.com site block not matched — leaving config unchanged (no-op)"
    rm -f "$TMP"; return 0
  fi
  if ! VERR="$(caddy validate --config "$TMP" --adapter caddyfile 2>&1)"; then
    echo "Caddy: candidate config invalid — no-op. validate output:"
    printf '%s\n' "$VERR" | head -25
    rm -f "$TMP"; return 0
  fi
  cp "$CF" "$BAK"
  cp "$TMP" "$CF"
  rm -f "$TMP"
  if systemctl reload caddy 2>/dev/null || caddy reload --config "$CF" --adapter caddyfile 2>/dev/null; then
    echo "Caddy: Cloudflare origin lock applied + reloaded (backup: $BAK)"
  else
    echo "Caddy: reload FAILED — restoring backup $BAK"
    cp "$BAK" "$CF"
    systemctl reload caddy 2>/dev/null || caddy reload --config "$CF" --adapter caddyfile 2>/dev/null || true
  fi
}
apply_caddy_cf_lock || true
